import { PointsTransaction } from './extract.model';

export type { PointsTransaction };

export enum OrderDetailStatus {
  IDLE = 'idle',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

export interface OrderDetailState {
  orderDetail?: PointsTransaction;
  status: OrderDetailStatus;
  error?: string;
  transactionId?: string;
}

export const EXTRACT_CONSTANTS = {
  DEFAULT_PAGE: 1,
  DEFAULT_PAGE_SIZE: 100,
  SUCCESS_RETURN_CODE: 200,
  BALANCE_SUCCESS_RETURN_CODE: 0,
} as const;

export const ANALYTICS_EVENTS = {
  EXTRACT_SUCCESS: {
    content_type: 'sucesso',
